 79→export const getNotificationsService = async (userId, { limit, before, unreadOnly = false }) => {
 80→    const fetchLimit = limit + 1;
 81→
 82→    let journalQuery = supabase
 83→        .from('notifications')
 84→        .select(NOTIFICATION_JOURNAL_SELECT)
 85→        .eq('receiver_id', userId)
 86→        .order('created_at', { ascending: false })
 87→        .order('id', { ascending: false })
 88→        .limit(fetchLimit);
 89→
 90→    let opinionQuery = supabase
 91→        .from('notification_opinions')
 92→        .select(NOTIFICATION_OPINION_SELECT)
 93→        .eq('receiver_id', userId)
 94→        .order('created_at', { ascending: false })
 95→        .order('id', { ascending: false })
 96→        .limit(fetchLimit);
 97→
 98→    if (unreadOnly) {
 99→        journalQuery = journalQuery.eq('read', false);
100→        opinionQuery = opinionQuery.eq('read', false);
101→    }
102→
103→    if (before) {
104→        journalQuery = journalQuery.lt('created_at', before);
105→        opinionQuery = opinionQuery.lt('created_at', before);
106→    }
107→
108→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
109→
110→    if (journalResult.error) {
111→        console.error('error fetching notifications:', journalResult.error);
112→        throw { status: 500, error: 'error fetching data from notification table' };
113→    }
114→    if (opinionResult.error) {
115→        console.error('error fetching opinion notifications:', opinionResult.error);
116→        throw { status: 500, error: 'error fetching data from notification_opinions table' };
117→    }
118→
119→    const journalNotifs = (journalResult.data || []).map(n => ({ ...n, source: 'journal' }));
120→    const opinionNotifs = (opinionResult.data || []).map(n => ({ ...n, source: 'opinion' }));
121→
122→    const merged = [...journalNotifs, ...opinionNotifs]
123→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
124→
125→    // Likes/bookmarks lookup only for journal notifications
126→    const journalIds = [...new Set(
127→        merged
128→            .filter(n => n.source === 'journal')
129→            .map(n => n.journal_id)
130→            .filter(Boolean)
131→    )];
132→
133→    let hasLikedResult = [];
134→    let hasBookMarkedResult = [];
135→    if (journalIds.length > 0) {
136→        const [hasLiked, hasBookMarked] = await Promise.all([
137→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
138→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
139→        ]);
140→
141→        if (hasLiked.error || hasBookMarked.error) {
142→            console.error('supabase error fetching likes/bookmarks:', hasLiked.error || hasBookMarked.error);
143→        }
144→        hasLikedResult = hasLiked.data || [];
145→        hasBookMarkedResult = hasBookMarked.data || [];
146→    }
147→
148→    const likedSet = new Set(hasLikedResult.map(l => l.journal_id));
149→    const bookmarkedSet = new Set(hasBookMarkedResult.map(b => b.journal_id));
150→
151→    const formatted = merged.map(notif => decorateNotificationMedia({
152→        ...notif,
153→        hasLiked: notif.source === 'journal' ? likedSet.has(notif.journal_id) : false,
154→        hasBookMarked: notif.source === 'journal' ? bookmarkedSet.has(notif.journal_id) : false
155→    }));
156→
157→    const hasMore = formatted.length > limit;
158→    const data = hasMore ? formatted.slice(0, limit) : formatted;
159→
