 238→const extractFromLexical = (contentJson) => {
 239→    try {
 240→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
 241→        const texts = [];
 242→        let firstImage = null;
 243→
 244→        const walk = (node) => {
 245→            if (!node || typeof node !== 'object') return;
 246→
 247→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
 248→            if (nodeType === 'text' && typeof node.text === 'string') {
 249→                texts.push(node.text);
 250→            }
 251→
 252→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
 253→            if (!firstImage && isImageNode) {
 254→                const image = imageFromNodeLike(node);
 255→                if (image) {
 256→                    firstImage = image;
 257→                }
 258→            }
 259→
 260→            if (Array.isArray(node.children)) {
 261→                node.children.forEach(walk);
 262→            }
 263→        };
 264→
 265→        if (parsed?.root) {
 266→            walk(parsed.root);
 267→        }
 268→
 269→        return {
 270→            text: normalizeWhitespace(texts.join(' ')),
 271→            image: firstImage
 272→        };
 273→    } catch {
 274→        return { text: '', image: null };
