 355→const isPrivateIpAddress = (ip) => {
 356→    const ipVersion = net.isIP(ip);
 357→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
 358→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
 359→    return true;
