 384→const evaluateShareImageCandidate = (rawUrl) => {
 385→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
 386→    if (!absoluteUrl) {
 387→        return {
 388→            ok: false,
 389→            reason: 'invalid_or_non_http_url',
 390→            resolvedUrl: null,
 391→        };
 392→    }
 393→
 394→    let path = '';
 395→    try {
 396→        const parsed = new URL(absoluteUrl);
 397→        path = String(parsed.pathname || '').toLowerCase();
 398→    } catch {
 399→        return {
 400→            ok: false,
 401→            reason: 'invalid_resolved_url',
 402→            resolvedUrl: null,
 403→        };
 404→    }
 405→
 406→    if (path.endsWith('.svg')) {
 407→        return {
 408→            ok: false,
 409→            reason: 'svg_not_supported_for_share_image',
 410→            resolvedUrl: absoluteUrl,
 411→        };
 412→    }
 413→
 414→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
 415→        return {
 416→            ok: false,
 417→            reason: 'unsafe_remote_url',
 418→            resolvedUrl: absoluteUrl,
 419→        };
 420→    }
 421→
 422→    return {
 423→        ok: true,
 424→        reason: 'ok',
 425→        resolvedUrl: absoluteUrl,
 426→    };
 427→};
