 651→    if (cached) {
 652→        res.set('Content-Type', 'image/jpeg');
 653→        res.set('Cache-Control', 'public, max-age=3600');
 654→        return res.send(cached);
 655→    }
 656→
 657→    await ensureShareFonts();
 658→
 659→    try {
 660→        const result = await getUserByUsernameService(username);
 661→        const user = result?.userData?.[0];
 662→        if (!user) {
 663→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 664→        }
 665→
 666→        const displayName = normalizeWhitespace(user.name) || username;
 667→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 668→        const bio = toPreviewText(user.bio || '', 120);
 669→
 670→        // ── Fetch background image ──
 671→        let bgBuffer = null;
 672→        const bgStyle = user.background || {};
 673→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 674→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 675→            : null;
 676→        const bgImageUrl = bgImageMatch?.[1];
 677→
 678→        if (bgImageUrl) {
 679→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 680→            if (bgEval.ok && bgEval.resolvedUrl) {
 681→                try {
 682→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 683→                    bgBuffer = remote.buffer;
 684→                } catch { /* use fallback gradient */ }
 685→            }
 686→        }
 687→
 688→        // ── Base layer: background or dark gradient ──
 689→        let baseLayer;
 690→        if (bgBuffer) {
 691→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 692→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 693→                .toBuffer();
 694→        } else {
 695→            // Use profile's solid background color if available, otherwise dark fallback
 696→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 697→                ? bgStyle.background.trim()
 698→                : null;
 699→            const gradientSvg = solidColor
 700→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 701→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 702→                </svg>`
 703→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 704→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 705→                        <stop offset="0%" stop-color="#1a1a2e"/>
 706→                        <stop offset="100%" stop-color="#16213e"/>
 707→                    </linearGradient></defs>
 708→                    <rect width="100%" height="100%" fill="url(#g)"/>
 709→                </svg>`;
 710→            baseLayer = await sharp(Buffer.from(gradientSvg))
 711→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 712→                .png()
 713→                .toBuffer();
 714→        }
 715→
 716→        // ── Dark overlay + circular avatar (parallel) ──
 717→        const avatarSize = 180;
 718→        const avatarUrl = user.image_url;
 719→
 720→        const overlayPromise = sharp(Buffer.from(
 721→            `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 722→                <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 723→            </svg>`
 724→        )).png().toBuffer();
 725→
 726→        const avatarPromise = (async () => {
 727→            if (!avatarUrl) return null;
 728→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 729→            if (!avatarEval.ok || !avatarEval.resolvedUrl) return null;
 730→            try {
 731→                const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 732→                const circleMask = Buffer.from(
 733→                    `<svg width="${avatarSize}" height="${avatarSize}">
 734→                        <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 735→                    </svg>`
 736→                );
 737→                const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 738→                    .resize(avatarSize, avatarSize, { fit: 'cover' })
 739→                    .png()
 740→                    .toBuffer();
 741→                return await sharp(resizedAvatar)
 742→                    .composite([{ input: circleMask, blend: 'dest-in' }])
 743→                    .png()
 744→                    .toBuffer();
 745→            } catch { return null; }
 746→        })();
 747→
 748→        const [overlayBuffer, avatarComposite] = await Promise.all([overlayPromise, avatarPromise]);
 749→
 750→        // ── Compose all layers ──
 751→        const composites = [
 752→            { input: overlayBuffer, top: 0, left: 0 },
 753→        ];
 754→
 755→        if (avatarComposite) {
 756→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 757→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 758→        }
 759→
 760→        const finalImage = await sharp(baseLayer)
 761→            .composite(composites)
 762→            .jpeg({ quality: 82, mozjpeg: true })
 763→            .toBuffer();
 764→
 765→        setShareImageCached(`profile:${username}`, finalImage);
 766→        res.set('Content-Type', 'image/jpeg');
 767→        res.set('Cache-Control', 'public, max-age=3600');
 768→        return res.send(finalImage);
 769→    } catch (err) {
 770→        console.error('profile share image route error:', err?.message || err);
 771→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 772→    }
 773→});
