 837→app.get('/share/post/:journalId/image', async (req, res) => {
 838→    const { journalId } = req.params;
 839→    const debugMode = isShareImageDebugRequest(req);
 840→
 841→    // Serve from cache if available (skip for debug)
 842→    if (!debugMode) {
 843→        const cached = getShareImageCached(`post:${journalId}`);
 844→        if (cached) {
 845→            res.set('Content-Type', 'image/jpeg');
 846→            res.set('Cache-Control', 'public, max-age=3600');
 847→            return res.send(cached);
 848→        }
 849→    }
 850→
 851→    await ensureShareFonts();
 852→    const debugPayload = {
 853→        ok: false,
 854→        fallback: false,
 855→        journalId,
 856→        stage: 'start',
 857→        reason: '',
 858→        meta: {
 859→            imageCandidateSource: null,
 860→            imageCandidateRaw: null,
 861→            imageCandidateResolved: null,
 862→            upstreamFinalUrl: null,
 863→            upstreamContentType: null,
 864→            upstreamBytes: null,
 865→            outputBytes: null,
 866→        },
 867→    };
 868→
 869→    const fallbackWithReason = (reason) => {
 870→        debugPayload.ok = false;
 871→        debugPayload.fallback = true;
 872→        debugPayload.stage = 'fallback';
 873→        debugPayload.reason = reason;
 874→        if (debugMode) {
 875→            return sendShareImageDebug(res, debugPayload);
 876→        }
 877→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 878→    };
 879→
 880→    try {
 881→        const journal = await getShareJournal(journalId);
 882→        debugPayload.stage = 'journal_loaded';
 883→        if (!journal) {
 884→            return fallbackWithReason('journal_not_found');
 885→        }
 886→
 887→        const shareMeta = buildShareMetaFromJournal(journal);
 888→        debugPayload.stage = 'candidate_extracted';
 889→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 890→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 891→
 892→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 893→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 894→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 895→            return fallbackWithReason(candidateEvaluation.reason);
 896→        }
 897→
 898→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 899→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 900→            return fallbackWithReason('candidate_is_default_fallback');
 901→        }
 902→
 903→        debugPayload.stage = 'fetching_upstream';
 904→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 905→        debugPayload.stage = 'upstream_loaded';
 906→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 907→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 908→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 909→
 910→        debugPayload.stage = 'converting_image';
 911→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 912→        debugPayload.stage = 'converted_image';
 913→        debugPayload.ok = true;
 914→        debugPayload.reason = 'ok';
 915→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 916→
 917→        if (debugMode) {
 918→            return sendShareImageDebug(res, debugPayload);
 919→        }
 920→
 921→        setShareImageCached(`post:${journalId}`, ogImageBuffer);
 922→        res.set('Content-Type', 'image/jpeg');
 923→        res.set('Cache-Control', 'public, max-age=3600');
 924→        return res.send(ogImageBuffer);
 925→    } catch (err) {
 926→        debugPayload.stage = 'error';
 927→        debugPayload.reason = err?.message || 'unknown_error';
 928→        console.error('share image route error:', err?.message || err);
 929→        return fallbackWithReason(debugPayload.reason);
 930→    }
 931→});
